sports_keywords = [
    'olympic', 'medal', 'tournament', 'championship', 'athlete', 'nba', 'nfl', 'nhl', 
    'mlb', 'fifa', 'uefa', 'world cup', 'super bowl', 'stanley cup', 'league', 'race', 
    'racing', 'formula 1', 'f1', 'nascar', 'quarterback', 'striker', 'goalkeeper', 
    'touchdown', 'homerun', 'wicket', 'inning', 'wimbledon', 'us open', 'french open', 
    'australian open', 'davis cup', 'fed cup', 'atp', 'wta', 'pga', 'lpga', 'gold medal', 
    'silver medal', 'bronze medal', 'record', 'team', 'game', 'sport', 'coach', 'player', 
    'match', 'win', 'loss', 'score', 'basket', 'bulls', 'lakers', 'yankees', 'red sox', 
    'cowboys', 'patriots', 'steelers', 'packers', 'giants', 'jets', 'knicks', 'nets', 
    'rangers', 'flyers', 'devils', 'islanders', 'met', 'phillies', 'eagles', '76ers',
    'marathon', 'sprint', 'relay', 'swimming', 'gymnastics', 'basketball', 'baseball',
    'football', 'soccer', 'tennis', 'hockey', 'golf', 'boxing', 'wrestling'
]

def get_keywords(text):
    text = text.lower()
    # Check strict word boundaries for short words like 'win', 'cup' to avoid 'windows', 'occupy'
